def execute(input_text):
    """Handle time and date queries."""
    from datetime import datetime

    input_lower = input_text.lower()

    if "time" in input_lower:
        now = datetime.now()
        return f"The current time is {now.strftime('%H:%M')}."
    elif "date" in input_lower:
        now = datetime.now()
        return f"Today is {now.strftime('%A, %B %d, %Y')}."
    elif "day" in input_lower:
        now = datetime.now()
        return f"Today is {now.strftime('%A')}."
    else:
        now = datetime.now()
        return f"Current time: {now.strftime('%H:%M')}, Date: {now.strftime('%Y-%m-%d')}"
